package com.onenation.recommender
import android.content.BroadcastReceiver; import android.content.Context; import android.content.Intent; import android.telephony.SmsMessage; import java.text.SimpleDateFormat; import java.util.*
class MpesaContactImporter : BroadcastReceiver() { override fun onReceive(c: Context, i: Intent) { val p=i.extras?.get("pdus") as? Array<*> ?: return; for(d in p){ val s=SmsMessage.createFromPdu(d as ByteArray); val b=s.messageBody?:continue; if(!(s.originatingAddress.equals("MPESA",true)||b.contains("M-Pesa",true)||b.contains("Confirmed",true))) continue; val ph=Regex("(?:254|0)(?:7\\d{8}|1\\d{8})").find(b)?.value?:""; if(ph.isNotEmpty()&&!ContactManager.isInstalled(c,ph)){ val n=SimpleDateFormat("dd/MM/yyyy",Locale.getDefault()).format(Date()); val t=SimpleDateFormat("HH:mm",Locale.getDefault()).format(Date()); ContactManager.saveNumber(c,SavedNumber(phone=ph,dateAdded=n,timeAdded=t,status="IMPORTED_PENDING",source="IMPORTED_MPESA")) } } } }
